/* DeckLinkAPIDispatch.cpp — Windows COM dispatch
**
** Provides the same factory functions as the Mac CFBundle-based dispatch,
** but creates DeckLink COM objects via CoCreateInstance.
**
** CLSIDs come from DeckLinkAPI_i.c, which is generated by midl.exe from
** DeckLinkAPI.idl.  DeckLinkAPI.h (also generated by midl.exe) declares
** all interface types and IIDs.
**
** CoInitializeEx must be called on the calling thread before using any
** of these functions.  DkDeckLinkOutput::DkDeckLinkOutput() does this
** via bmdPlatformInit().
*/

#include "DeckLinkAPI.h"
#include <objbase.h>

static HRESULT createInstance(REFCLSID clsid, REFIID iid, void** ppv)
{
    return CoCreateInstance(clsid, nullptr, CLSCTX_ALL, iid, ppv);
}

bool IsDeckLinkAPIPresent()
{
    IDeckLinkIterator* iter = nullptr;
    HRESULT hr = createInstance(CLSID_CDeckLinkIterator,
                                 IID_IDeckLinkIterator, (void**)&iter);
    if (SUCCEEDED(hr) && iter) { iter->Release(); return true; }
    return false;
}

IDeckLinkIterator* CreateDeckLinkIteratorInstance()
{
    IDeckLinkIterator* p = nullptr;
    createInstance(CLSID_CDeckLinkIterator, IID_IDeckLinkIterator, (void**)&p);
    return p;
}

IDeckLinkAPIInformation* CreateDeckLinkAPIInformationInstance()
{
    IDeckLinkAPIInformation* p = nullptr;
    createInstance(CLSID_CDeckLinkAPIInformation,
                   IID_IDeckLinkAPIInformation, (void**)&p);
    return p;
}

